#include <limits.h>
#include <string.h>

// Function to calculate the total cost of a given path
int calculateCost(int cost[][16], int path[], int n) {
    int totalCost = 0;
    for (int i = 0; i < n - 1; ++i) {
        totalCost += cost[path[i]][path[i + 1]];
    }
    totalCost += cost[path[n - 1]][path[0]];  // Return to starting city
    return totalCost;
}

// Function to generate all permutations of cities and calculate the minimum cost
int tsp(int cost[][16], int n) {
    int cities[16];
    for (int i = 0; i < n; ++i) {
        cities[i] = i;
    }

    int minCost = INT_MAX;

    // Generate all permutations of cities (except the first city, which is fixed)
    do {
        int costOfCurrentPath = calculateCost(cost, cities, n);
        if (costOfCurrentPath < minCost) {
            minCost = costOfCurrentPath;
        }
    } while (next_permutation(cities, cities + n));  // Keep start city fixed

    return minCost;
}

int next_permutation(int *begin, int *end) {
    if (begin == end)
        return 0;

    int *i = end;
    --i;
    if (begin == i)
        return 0;

    int *j = i;
    --i;
    if (*i < *j) {
        int *k = end;
        while (!(*i < *--k))
            ;
        int temp = *i;
        *i = *k;
        *k = temp;
        std::reverse(j, end);
        return 1;
    }

    while (j-- > begin) {
        if (*begin < *j) {
            int *k = end;
            while (!(*j < *--k))
                ;
            int temp = *j;
            *j = *k;
            *k = temp;
            std::reverse(begin + 1, end);
            return 1;
        }
    }
    return 0;
}

