using namespace std;

// Function to calculate the total cost of a given path
int calculateCost(const vector<vector<int>>& cost, const vector<int>& path) {
    int totalCost = 0;
    for (int i = 0; i < path.size() - 1; ++i) {
        totalCost += cost[path[i]][path[i + 1]];
    }
    totalCost += cost[path[path.size() - 1]][path[0]];  // Return to starting city
    return totalCost;
}

// Function to generate all permutations of cities and calculate the minimum cost
int tsp(const vector<vector<int>>& cost) {
    int n = cost.size();
    vector<int> cities(n);
    for (int i = 0; i < n; ++i) {
        cities[i] = i;
    }

    int minCost = INT_MAX;
    do {
        int costOfCurrentPath = calculateCost(cost, cities);
        minCost = min(minCost, costOfCurrentPath);
    } while (next_permutation(cities.begin() + 1, cities.end()));  // Keep start city fixed

    return minCost;
}

