const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;

// Function to calculate the total cost of a given path
function calculateCost(cost, path) {
    let totalCost = 0;
    for (let i = 0; i < path.length - 1; ++i) {
        totalCost += cost[path[i]][path[i + 1]];
    }
    totalCost += cost[path[path.length - 1]][path[0]];  // Return to starting city
    return totalCost;
}

// Function to generate all permutations of cities and calculate the minimum cost
function tsp(cost) {
    let n = cost.length;
    let cities = Array.from({ length: n }, (_, i) => i);

    let minCost = Infinity;

    // Generate all permutations of cities (except the first city, which is fixed)
    let permutations = permute(cities.slice(1));

    // Check each permutation
    for (let perm of permutations) {
        let path = [0].concat(perm);  // Fix the starting city at index 0
        let costOfCurrentPath = calculateCost(cost, path);
        minCost = Math.min(minCost, costOfCurrentPath);
    }

    return minCost;
}

// Function to generate permutations of cities (except the first city)
function permute(arr) {
    if (arr.length === 1) return [arr];
    let result = [];
    for (let i = 0; i < arr.length; i++) {
        let rest = arr.slice(0, i).concat(arr.slice(i + 1));
        for (let p of permute(rest)) {
            result.push([arr[i]].concat(p));
        }
    }
    return result;
}

// Main function to take input and call the TSP function
function main() {
    let n = parseInt(lines[idx++]);  // Number of cities
    let cost = [];

    // Input the cost matrix
    for (let i = 0; i < n; i++) {
        cost.push(lines[idx++].split(' ').map(Number));
    }

    // Calling the TSP function and getting the result
    let result = tsp(cost);

    // Output the minimum cost
    console.log(result);
}

